class Solution {
    public String arrangeWords(String text) {
        String[] words = text.split(" ");
        String[][] wordLength = new String[words.length][2];
        for (int i = 0; i < words.length; i++) {
            wordLength[i][0] = words[i];
            wordLength[i][1] = String.valueOf(words[i].length());
        }
        Arrays.sort(wordLength, (a, b) -> {
            if (a[1].equals(b[1])) {
                return Integer.compare(Arrays.asList(words).indexOf(a[0]), Arrays.asList(words).indexOf(b[0]));
            } else {
                return a[1].compareTo(b[1]);
            }
        });
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < wordLength.length; i++) {
            if (i == 0) {
                sb.append(Character.toUpperCase(wordLength[i][0].charAt(0)));
                sb.append(wordLength[i][0].substring(1).toLowerCase());
            } else {
                sb.append(" ");
                sb.append(wordLength[i][0].toLowerCase());
            }
        }
        return sb.toString();
    }
}
